'alevel-bio-coordination': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><defs><style>@keyframes co_p{0%{transform:translateX(-80px);opacity:0}60%{opacity:1}100%{transform:translateX(0);opacity:.8}}.co_imp{animation:co_p 2.5s linear infinite}</style></defs><ellipse cx="100" cy="150" rx="35" ry="22" fill="var(--surface)" stroke="var(--accent)" stroke-width="2"/><circle cx="100" cy="150" r="10" fill="var(--accent)" fill-opacity=".4"/><text x="100" y="182" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">cell body</text><line x1="135" y1="150" x2="270" y2="150" stroke="var(--text-dim)" stroke-width="2.5"/><circle class="co_imp" cx="270" cy="150" r="6" fill="var(--accent)" fill-opacity=".9"/><text x="200" y="168" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">axon (impulse →)</text><rect x="272" y="130" width="60" height="40" rx="8" fill="var(--surface)" stroke="var(--border)" stroke-width="1.5"/><text x="302" y="150" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">synapse</text><text x="302" y="162" font-size="6" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">neurotransmitter</text><rect x="60" y="40" width="90" height="26" rx="5" fill="var(--surface)" stroke="var(--border)" stroke-width="1.5"/><text x="105" y="57" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">nervous (fast)</text><rect x="250" y="40" width="100" height="26" rx="5" fill="var(--surface)" stroke="var(--border)" stroke-width="1.5"/><text x="300" y="57" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">hormonal (slow)</text><text x="200" y="240" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">resting potential: −70 mV → action potential: +40 mV</text><text x="200" y="24" font-size="11" fill="var(--text)" font-family="sans-serif" font-weight="bold" text-anchor="middle">Coordination</text></svg>`,

