'alevel-chem-polymerisation': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><defs><style>@keyframes po_g{0%{transform:scaleX(.2)}100%{transform:scaleX(1)}}.po_ch{transform-origin:left center;animation:po_g 2.5s ease-out forwards}</style></defs><text x="200" y="55" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">Addition: n CH₂=CH₂ → -(CH₂-CH₂)ₙ-</text><rect class="po_ch" x="40" y="70" width="320" height="28" rx="4" fill="var(--accent)" fill-opacity=".15" stroke="var(--accent)" stroke-width="1.5"/><text x="200" y="89" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">polyethene chain growing →</text><text x="200" y="130" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">Condensation: monomer + monomer → polymer + H₂O</text><line x1="60" y1="155" x2="170" y2="155" stroke="var(--accent)" stroke-width="2"/><line x1="170" y1="155" x2="230" y2="155" stroke="var(--border)" stroke-width="1.5" stroke-dasharray="4,2"/><line x1="230" y1="155" x2="340" y2="155" stroke="var(--accent)" stroke-width="2"/><rect x="60" y="140" width="110" height="30" rx="4" fill="var(--surface)" stroke="var(--accent)" stroke-width="1.5"/><rect x="230" y="140" width="110" height="30" rx="4" fill="var(--surface)" stroke="var(--accent)" stroke-width="1.5"/><text x="115" y="158" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">diamine</text><text x="285" y="158" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">dicarboxylic acid</text><text x="200" y="200" font-size="8" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">nylon (polyamide) | terylene (polyester)</text><text x="200" y="230" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">biodegradability · recycling considerations</text><text x="200" y="24" font-size="11" fill="var(--text)" font-family="sans-serif" font-weight="bold" text-anchor="middle">Polymerisation</text></svg>`,

'alevel-chem-organic-synthesis': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><defs><style>@keyframes os_f{0%,100%{opacity:.35}50%{opacity:1}}.os_a{animation:os_f 2s ease-in-out infinite}.os_b{animation:os_f 2s ease-in-out infinite .5s}.os_c{animation:os_f 2s ease-in-out infinite 1s}.os_d{animation:os_f 2s ease-in-out infinite 1.5s}</style><marker id="osa" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto"><path d="M0,0 L6,3 L0,6 Z" fill="var(--border)"/></marker></defs><text x="200" y="15" text-anchor="middle" font-size="11" font-weight="bold" fill="var(--text)" font-family="sans-serif">Organic Synthesis</text><ellipse class="os_a" cx="70" cy="155" rx="52" ry="23" fill="var(--surface)" stroke="var(--accent)" stroke-width="2"/><text x="70" y="152" text-anchor="middle" font-size="8" font-weight="bold" fill="var(--accent)" font-family="sans-serif">ALKANE</text><text x="70" y="165" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">CₙH₂ₙ₊₂</text><ellipse class="os_b" cx="200" cy="62" rx="58" ry="23" fill="var(--surface)" stroke="var(--border)" stroke-width="2"/><text x="200" y="59" text-anchor="middle" font-size="8" font-weight="bold" fill="var(--text)" font-family="sans-serif">HALOALKANE</text><text x="200" y="72" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">R—X</text><ellipse class="os_c" cx="340" cy="130" rx="52" ry="23" fill="var(--surface)" stroke="var(--border)" stroke-width="2"/><text x="340" y="127" text-anchor="middle" font-size="8" font-weight="bold" fill="var(--text)" font-family="sans-serif">ALKENE</text><text x="340" y="140" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">C=C</text><ellipse class="os_d" cx="310" cy="228" rx="52" ry="23" fill="var(--surface)" stroke="var(--accent)" stroke-width="2"/><text x="310" y="225" text-anchor="middle" font-size="8" font-weight="bold" fill="var(--accent)" font-family="sans-serif">ALCOHOL</text><text x="310" y="238" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">R—OH</text><ellipse cx="130" cy="258" rx="62" ry="23" fill="var(--surface)" stroke="var(--border)" stroke-width="2"/><text x="130" y="255" text-anchor="middle" font-size="7.5" font-weight="bold" fill="var(--text)" font-family="sans-serif">CARBONYL/ACID</text><text x="130" y="268" text-anchor="middle" font-size="7" fill="var(--text-dim)" font-family="sans-serif">R-CHO / R-COOH</text><line x1="118" y1="142" x2="155" y2="80" stroke="var(--border)" stroke-width="1.2" marker-end="url(#osa)"/><text x="120" y="108" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">X₂, UV</text><line x1="252" y1="72" x2="293" y2="118" stroke="var(--border)" stroke-width="1.2" marker-end="url(#osa)"/><text x="280" y="92" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">KOH/EtOH,Δ</text><line x1="238" y1="78" x2="278" y2="212" stroke="var(--border)" stroke-width="1.2" marker-end="url(#osa)"/><text x="268" y="150" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">NaOH/aq</text><line x1="277" y1="215" x2="242" y2="83" stroke="var(--border)" stroke-width="1.2" stroke-dasharray="3,2" marker-end="url(#osa)"/><text x="242" y="157" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">HBr</text><line x1="303" y1="148" x2="318" y2="208" stroke="var(--border)" stroke-width="1.2" marker-end="url(#osa)"/><text x="326" y="182" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">H₂O/H⁺</text><line x1="260" y1="240" x2="195" y2="262" stroke="var(--border)" stroke-width="1.2" marker-end="url(#osa)"/><text x="224" y="252" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">[O]Cr₂O₇²⁻</text><line x1="295" y1="125" x2="122" y2="152" stroke="var(--border)" stroke-width="1.2" stroke-dasharray="3,2" marker-end="url(#osa)"/><text x="205" y="133" font-size="6.5" fill="var(--text-dim)" font-family="sans-serif">H₂/Ni</text></svg>`,

